parameters.inputSchema:
{
  "type": "array",
  "items": {
    "type": "object",
    "properties": {
      "date": {
        "type": "string",
        "description": "The date of the transaction in YYYY-MM-DD format."
      },
      "description": {
        "type": "string",
        "description": "The full description of the transaction, merged if multi-line."
      },
      "debit": {
        "type": "number",
        "description": "The amount outgoing (money out). Use 0 if none."
      },
      "credit": {
        "type": "number",
        "description": "The amount incoming (money in). Use 0 if none."
      },
      "balance": {
        "type": "number",
        "description": "The running balance after this transaction."
      }
    },
    "required": ["date", "description", "debit", "credit", "balance"]
  }
}

parameters.jsCode:
// Get all incoming items from the OCR node
const allItems = $input.all();

// Use .flatMap and .map to extract text from every page dynamically
const combinedText = allItems
  .flatMap(item => item.json.responses || []) // Handle potential top-level responses array
  .flatMap(response => response.responses || []) // Drill into the sub-responses array
  .map(page => page.fullTextAnnotation?.text || '') // Extract the text safely
  .filter(text => text.length > 0) // Remove any empty pages
  .join('\n\n--- PAGE BREAK ---\n\n'); // Join everything into one string

// Return a single object for the Information Extractor
return [
  {
    json: {
      combined_text: combinedText,
      total_pages: allItems.length,
      processed_at: new Date().toISOString()
    }
  }
];

// Get the first item from the OCR node
const item = $input.first();

// Extract text from the standard Google Vision response structure
// Accesses the first response in the array and gets the full text
const extractedText = item.json.responses?.[0]?.fullTextAnnotation?.text || '';

// Return a single object for the Information Extractor
return [
  {
    json: {
      combined_text: extractedText,
      page_count: 1,
      processed_at: new Date().toISOString()
    }
  }
];
